    .AsIChatClient();

// --- Shared state for the note-taking tool ---
var notebook = new List<(string Title, string Content)>();

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWebAsync, nameof(SearchWebAsync)),
    AIFunctionFactory.Create(SaveNote, nameof(SaveNote)),
