 using System.ComponentModel;
 using System.Text.RegularExpressions;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

 // --- Build the IChatClient ---
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Shared state for the note-taking tool ---
 var notebook = new List<(string Title, string Content)>();

 // --- Define tools ---
 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(SearchWebAsync, nameof(SearchWebAsync)),
     AIFunctionFactory.Create(SaveNote, nameof(SaveNote)),
     AIFunctionFactory.Create(ReadNotes, nameof(ReadNotes)),
 };

 // --- Create the research agent ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. Your job is to thoroughly research a topic provided by the user.

         Follow this process:
         1. Break the topic into 2-3 focused search queries.
         2. Use SearchWebAsync for each query.
         3. Use SaveNote to record important findings (include source URLs).
         4. After all searches, use ReadNotes to review your collected notes.
         5. Produce a well-organized summary with sections, key facts, and source citations.

         Be thorough but concise. Prioritize recent, factual information.
         """,
     name: "ResearchAgent",
     description: "Researches topics via web search and summarizes findings",
     tools: tools);

 // --- Get topic from the user ---
 string topic;
 if (args.Length > 0)
 {
     topic = string.Join(' ', args);
 }
 else
 {
     Console.Write("Enter a research topic: ");
     topic = Console.ReadLine()?.Trim() ?? string.Empty;
 }

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.Error.WriteLine("No topic provided. Exiting.");
     return 1;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 // --- Run the agent ---
 var response = await agent.RunAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}");

 Console.WriteLine("\n📋 Research Summary");
 Console.WriteLine(new string('─', 60));
 Console.WriteLine(response.Text);
 Console.WriteLine(new string('─', 60));
 Console.WriteLine($"\n📝 Notes collected: {notebook.Count}");
 return 0;

