 [Description("Searches the web for the given query and returns relevant result snippets with URLs.")]
 async Task<string> SearchWebAsync(
     [Description("The search query to look up on the web")] string query)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");

     using var http = new HttpClient();
     http.DefaultRequestHeaders.UserAgent.ParseAdd(
         "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

     try
     {
         var encoded = Uri.EscapeDataString(query);
         var url = $"https://html.duckduckgo.com/html/?q={encoded}";
         var html = await http.GetStringAsync(url);

         var results = ParseSearchResults(html);
         if (results.Count == 0)
             return "No results found for this query.";

         return string.Join("\n\n", results.Take(5));
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}";
     }
 }

 [Description("Saves a research note with a short title and detailed content.")]
 string SaveNote(
     [Description("A short title for the note")] string title,
     [Description("The detailed content of the note, including any source URLs")] string content)
 {
     notebook.Add((title, content));
     Console.WriteLine($"  📝 Note saved: \"{title}\"");
     return $"Note \"{title}\" saved. Total notes: {notebook.Count}.";
 }

 [Description("Reads all previously saved research notes.")]
 string ReadNotes()
 {
     if (notebook.Count == 0)
         return "No notes saved yet.";

     return string.Join("\n\n", notebook.Select((n, i) =>
         $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
 }

 // ---------------------------------------------------------------------------
 // HTML parsing helper – extracts titles, snippets, and URLs from DuckDuckGo
 // ---------------------------------------------------------------------------

 static List<string> ParseSearchResults(string html)
 {
     var results = new List<string>();

     // DuckDuckGo wraps each result in <div class="result ...">
     var resultBlocks = Regex.Matches(html,
         @"<div[^>]*class=""[^""]*result[^""]*""[^>]*>(.*?)</div>\s*</div>",
         RegexOptions.Singleline | RegexOptions.IgnoreCase);

     foreach (Match block in resultBlocks)
     {
         var inner = block.Groups[1].Value;

         // Extract the title from <a class="result__a" ...>
         var titleMatch = Regex.Match(inner,
             @"<a[^>]*class=""result__a""[^>]*>(.*?)</a>",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);

         // Extract the snippet from <a class="result__snippet" ...>
         var snippetMatch = Regex.Match(inner,
             @"<a[^>]*class=""result__snippet""[^>]*>(.*?)</a>",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);

         // Extract the URL from <a class="result__url" ...>
         var urlMatch = Regex.Match(inner,
             @"<a[^>]*class=""result__url""[^>]*[^>]*>(.*?)</a>",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);

         if (!titleMatch.Success && !snippetMatch.Success)
             continue;

         var title = StripHtml(titleMatch.Groups[1].Value).Trim();
         var snippet = StripHtml(snippetMatch.Groups[1].Value).Trim();
         var resultUrl = StripHtml(urlMatch.Groups[1].Value).Trim();

         results.Add($"Title: {title}\nURL: {resultUrl}\nSnippet: {snippet}");
     }

     // Fallback: try extracting <a class="result__a"> links if block parsing found nothing
     if (results.Count == 0)
     {
         var links = Regex.Matches(html,
             @"<a[^>]*class=""result__a""[^>]*href=""([^""]*)""[^>]*>(.*?)</a>",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);

         foreach (Match link in links)
         {
             var href = link.Groups[1].Value;
             var text = StripHtml(link.Groups[2].Value).Trim();
             if (!string.IsNullOrEmpty(text))
                 results.Add($"Title: {text}\nURL: {href}");
         }
     }

     return results;
 }

 static string StripHtml(string html) =>
     Regex.Replace(html, @"<[^>]+>", string.Empty).Trim();
